sql:
SELECT journal_title 
FROM journals 
WHERE impact_factor = (SELECT MAX(impact_factor) FROM journals);

SELECT publication_id, COUNT(*) AS total_authors
FROM publication_authors
GROUP BY publication_id;

SELECT users.user_name, users.role, users.is_active, institutions.institution_name, institutions.contact_email
FROM users
INNER JOIN institutions ON users.institution_id = institutions.institution_id;

SELECT 
    (SELECT COUNT(user_id) FROM users WHERE is_active = 1) AS active_users,
    (SELECT COUNT(*) FROM institutions) AS total_institutions;

